import React from 'react';
import Hero from './Hero';
import About from './About';
import Features from './Features';
import Programs from './Programs';
import Testimonials from './Testimonials';
import Newsletter from './Newsletter';

const Home = () => {
  return (
    <>
      <Hero />
      <About />
      <Features />
      <Programs />
      <Testimonials />
      <Newsletter />
    </>
  );
};

export default Home;
